                      })}
                    </tbody>
                  </table>
                </div>
              ) : (
                <div className="manager-empty-state">
                  <strong>No line items found</strong>
                  <p>This document does not currently have any detail rows to display.</p>
                </div>
              )}
            </section>
          </div>
        ) : null}
      </div>
    </MainLayout>
  );
};

export default ManagerDashboardPage;
